def has_directed_cycle(graph):
    def dfs(node, visited, rec_stack):
        if node in rec_stack:
            return True
        if node in visited:
            return False
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph.get(node, []):
            if dfs(neighbor, visited, rec_stack):
                return True
        rec_stack.remove(node)
        return False

