def parse_nested_list(text):
    if not (text.startswith('[') and text.endswith(']')):
        raise ValueError("Root must be a list")

    def parse(s):
        s = s.strip()
        if s[0] == '[' and s[-1] == ']':
            return [parse(x.strip()) for x in re.split(r',\s*', s[1:-1])]
        elif s.isdigit():
            return int(s)
        else:
            raise ValueError("Non-integer leaf found")

    try:
        result = parse(text)
    except Exception as e:
        raise ValueError("Invalid input") from e

    return result

def evaluate_rpn(tokens):
    stack = []
    for token in tokens:
        if token.isdigit():
            stack.append(int(token))
        else:
            b = stack.pop()
            a = stack.pop()
            if token == '+':
                stack.append(a + b)
            elif token == '-':
                stack.append(a - b)
            elif token == '*':
                stack.append(a * b)
            elif token == '/':
                stack.append(int(a / b))
            else:
                raise ValueError("Invalid token")
    return stack[0]

