def interleaving_string(first, second, target):
    if len(target) != len(first) + len(second):
        return False
    dp = [[False] * (len(second) + 1) for _ in range(len(first) + 1)]
    dp[0][0] = True
    for i in range(len(first)):
        dp[i+1][0] = dp[i][0] and first[i] == target[i]
    for j in range(len(second)):
        dp[0][j+1] = dp[0][j] and second[j] == target[j]
    for i in range(len(first)):
        for j in range(len(second)):
            dp[i+1][j+1] = (dp[i][j+1] and first[i] == target[i+j+1]) or (dp[i+1][j] and second[j] == target[i+j+1])
    return dp[-1][-1]

import heapq

def prim_mst_weight(graph, start):
    visited = set()
    min_heap = [(0, start)]
    total_weight = 0

    while min_heap:
        weight, node = heapq.heappop(min_heap)

        if node in visited:
            continue

        visited.add(node)
        total_weight += weight

        for neighbor, w in graph[node].items():
            if neighbor not in visited:
                heapq.heappush(min_heap, (w, neighbor))

    if len(visited) != len(graph):
        raise ValueError("Graph is disconnected")

    return total_weight

