from datetime import timedelta

def business_days_between(start, end, holidays=()):
    if end < start:
        return -business_days_between(end, start, holidays)
    delta = end - start
    days = delta.days + 1
    weekend_count = sum(1 for i in range(days) if (start + timedelta(i)).weekday() >= 5)
    holiday_count = sum(1 for h in holidays if start <= h < end)
    return max(0, days - weekend_count - holiday_count)

